INSERT INTO "Testimonial" ("id", "author", "role", "sourceLabel", "rating", "text", "avatarUrl", "isApproved", "isFeatured", "displayOrder", "createdAt") VALUES ('cmr6uwxcy007ehi7am0gsn9pi', 'Daniel R.', 'Regular since 2009', NULL, 5, 'Best fade in Milton, hands down. Jo and the team treat you like family every single visit.', NULL, 1, 1, 0, 1783199454947);
INSERT INTO "Testimonial" ("id", "author", "role", "sourceLabel", "rating", "text", "avatarUrl", "isApproved", "isFeatured", "displayOrder", "createdAt") VALUES ('cmr6uwxcy007fhi7an3pk7pof', 'Anthony M.', 'Local', NULL, 5, 'Old-school barbershop with modern skills. The hot-towel shave is an experience everyone should try.', NULL, 1, 1, 1, 1783199454947);
INSERT INTO "Testimonial" ("id", "author", "role", "sourceLabel", "rating", "text", "avatarUrl", "isApproved", "isFeatured", "displayOrder", "createdAt") VALUES ('cmr6uwxcy007ghi7arrn7u257', 'Sam K.', NULL, NULL, 5, 'Cosimo nailed exactly what I asked for. Sharp line-up and a clean blend — I won''t go anywhere else.', NULL, 1, 1, 2, 1783199454947);
INSERT INTO "Testimonial" ("id", "author", "role", "sourceLabel", "rating", "text", "avatarUrl", "isApproved", "isFeatured", "displayOrder", "createdAt") VALUES ('cmr6uwxcy007hhi7advgmraz7', 'George P.', 'Customer for 40 years', NULL, 5, 'Been coming here since Mike ran the chair. Same quality, same great conversation. A Milton institution.', NULL, 1, 1, 3, 1783199454947);
INSERT INTO "Testimonial" ("id", "author", "role", "sourceLabel", "rating", "text", "avatarUrl", "isApproved", "isFeatured", "displayOrder", "createdAt") VALUES ('cmr6uwxcy007ihi7a0r2wg864', 'Liam T.', NULL, NULL, 5, 'Booked online in two minutes and was in the chair on time. Loved the whole experience.', NULL, 1, 0, 4, 1783199454947);
INSERT INTO "Testimonial" ("id", "author", "role", "sourceLabel", "rating", "text", "avatarUrl", "isApproved", "isFeatured", "displayOrder", "createdAt") VALUES ('cmr6uwxcy007jhi7aieb1gioz', 'Priya S.', 'Brought my son in', NULL, 5, 'So patient and kind with my 6-year-old''s first real haircut. Highly recommend for kids.', NULL, 1, 0, 5, 1783199454947);
INSERT INTO "SiteSettings" ("id", "businessName", "tagline", "description", "logoUrl", "faviconUrl", "heroImageUrl", "heroHeadline", "heroSubheadline", "heroPrimaryCtaText", "heroPrimaryCtaHref", "heroSecondaryCtaText", "heroSecondaryCtaHref", "aboutTitle", "aboutBody", "phone", "email", "address", "city", "region", "postalCode", "country", "mapEmbedUrl", "latitude", "longitude", "timezone", "currency", "instagramUrl", "facebookUrl", "tiktokUrl", "youtubeUrl", "googleReviewUrl", "navBookText", "navBookHref", "showShopInNav", "showCartButton", "primaryAccentHex", "secondaryAccentHex", "seoTitle", "seoDescription", "openGraphImageUrl", "slotIntervalMin", "minNoticeMin", "maxAdvanceDays", "maxPerSlot", "cancellationCutoffHours", "depositRequired", "allowAnyBarber", "requireCustomerName", "requireCustomerEmail", "requireCustomerPhone", "requireCustomerNotes", "taxRatePct", "bookingPolicy", "cancellationPolicy", "latePolicy", "noShowPolicy", "depositPolicy", "privacyPolicy", "bookingInstructions", "bookingHelpText", "bookingNotesHelpText", "bookingConfirmationTitle", "bookingConfirmationText", "enableEmail", "enableSms", "updatedAt") VALUES ('singleton', 'Joseph & Mike''s Barbershop', 'A Cut Above — Where Tradition Meets Modernity', 'Milton''s downtown barbershop since 1966. Quality haircuts, fades, shaves and styling — walk-in or by appointment.', NULL, NULL, 'https://images.unsplash.com/photo-1503951914875-452162b0f3f1?auto=format&fit=crop&w=1600&h=1100&q=88', 'A Cut Above', 'Three generations of master barbers in the heart of downtown Milton. Where tradition meets modern craft.', 'Book Your Appointment', '/book', 'View Services', '/services', 'Our Story', 'Established in 1966 by Mike Boughton, Joseph & Mike''s is a downtown landmark — a place where relationships are forged, deep thoughts are shared, and plenty of laughs are had. After more than 50 years at the helm, Mike passed the reins to Joseph. Today, Jo runs the shop alongside his son Cosimo. The Pedulla family continues to uphold Mike''s legacy with the same personalized service the Milton community has loved for decades.', '905-878-3916', 'hello@josephandmikes.com', '148 Main Street East', 'Milton', 'Ontario', 'L9T 1N6', 'Canada', 'https://maps.google.com/maps?q=148+Main+Street+East,+Milton,+Ontario&t=&z=15&ie=UTF8&iwloc=&output=embed', 43.5183, -79.8774, 'America/Toronto', 'CAD', 'https://instagram.com', 'https://facebook.com', NULL, NULL, 'https://g.page', 'Book Now', '/book', 1, 1, '#c4942b', '#8b1e1e', NULL, NULL, NULL, 15, 120, 60, 1, 12, 0, 1, 1, 0, 0, 0, 13, 'Please arrive 5 minutes before your appointment. Walk-ins are always welcome based on availability.', 'You can reschedule or cancel free of charge up to 12 hours before your appointment.', 'If you are running late, please call the shop so we can protect the rest of the day''s schedule.', 'Missed appointments may require a deposit before future bookings.', 'Deposits, when enabled, are applied toward your service total.', 'We only use your contact details to manage your booking or respond to your message.', 'Choose a service, barber, date and time. You can manage your appointment from your confirmation link.', 'Real-time availability is shown from the shop schedule.', 'Style references, allergies, accessibility needs or anything the barber should know.', 'You''re booked in!', 'A confirmation is on its way. We can''t wait to see you.', 1, 1, 1783199454394);
