INSERT INTO "FaqItem" ("id", "question", "answer", "category", "isActive", "displayOrder", "createdAt", "updatedAt") VALUES ('cmr6uwx1d0013hi7a749j9nmg', 'Do you take walk-ins?', 'Yes. Walk-ins are welcome when a chair is free, and booking ahead is the best way to guarantee a time.', 'Booking', 1, 0, 1783199454529, 1783199454529);
INSERT INTO "FaqItem" ("id", "question", "answer", "category", "isActive", "displayOrder", "createdAt", "updatedAt") VALUES ('cmr6uwx1d0014hi7abog5qkb7', 'Can I choose my barber?', 'Yes. Pick a specific barber or choose any available barber for the fastest options.', 'Booking', 1, 1, 1783199454529, 1783199454529);
INSERT INTO "FaqItem" ("id", "question", "answer", "category", "isActive", "displayOrder", "createdAt", "updatedAt") VALUES ('cmr6uwx1d0015hi7a4s4vcrif', 'How do I reschedule?', 'Use the secure manage-booking link from your confirmation screen or message.', 'Booking', 1, 2, 1783199454529, 1783199454529);
INSERT INTO "PolicyItem" ("id", "key", "title", "body", "isActive", "displayOrder", "createdAt", "updatedAt") VALUES ('cmr6uwx0s000xhi7a9zb3guzz', 'cancellation', 'Cancellation policy', 'You can reschedule or cancel free of charge up to 12 hours before your appointment.', 1, 0, 1783199454508, 1783199454508);
INSERT INTO "PolicyItem" ("id", "key", "title", "body", "isActive", "displayOrder", "createdAt", "updatedAt") VALUES ('cmr6uwx0v000yhi7a4ay9kvuw', 'late', 'Late policy', 'If you are running late, please call the shop. We may need to shorten or reschedule appointments that arrive too late.', 1, 1, 1783199454512, 1783199454512);
INSERT INTO "PolicyItem" ("id", "key", "title", "body", "isActive", "displayOrder", "createdAt", "updatedAt") VALUES ('cmr6uwx0z000zhi7a5hw9wswy', 'no_show', 'No-show policy', 'Missed appointments may require a deposit before future bookings.', 1, 2, 1783199454515, 1783199454515);
INSERT INTO "PolicyItem" ("id", "key", "title", "body", "isActive", "displayOrder", "createdAt", "updatedAt") VALUES ('cmr6uwx120010hi7akxedese8', 'deposit', 'Deposit/payment policy', 'Deposits, when enabled, are applied toward your service total.', 1, 3, 1783199454519, 1783199454519);
INSERT INTO "PolicyItem" ("id", "key", "title", "body", "isActive", "displayOrder", "createdAt", "updatedAt") VALUES ('cmr6uwx150011hi7a8e5qbhgz', 'privacy', 'Privacy note', 'We only use your contact details to manage your booking or respond to your message.', 1, 4, 1783199454522, 1783199454522);
